Author Name: **Art. FR**
Original Redmine Message: 2172 from https://www.veripool.org



---

Hello,
can anyone spot what's wrong with my example. The simulation produces good printf results but the VCD file is empty.
Thanks

Command line
```
verilator -Wall --trace --cc inv.v --exe sim_main.cpp
cd obj_dir
make -j -f Vinv.mk Vinv
./obj_dir/Vinv

```

verilog file inv.v
```
module inv(input in, output out);
    initial
      $display("hello from %m");   
    wire out = ~in;
endmodule

```

sim_main.cpp
```
#include "Vinv.h"
#include "verilated.h"
#include "verilated_vcd_c.h"
int main(int argc, char **argv, char **env) {
  int time;
  Verilated::commandArgs(argc, argv);
  Vinv* top = new Vinv;

  Verilated::traceEverOn(true);
  VerilatedVcdC* tfp = new VerilatedVcdC;
  top->trace (tfp, 99);
  tfp->open ("./simx.vcd");

  top->in =0;

  for (time=0; time<20; time++)  {
     top->in = (time %2) ? top->in : ~top->in;
     top->eval ();
     printf("in:%d, out:%d\n", top->in &1, top->out);
     tfp->dump (time);
     if (Verilated::gotFinish())
       exit(0);
  }
  delete top;
  exit(0);
}

```

